// Query Loki for OpenClaw error logs from the last 5 minutes
// Exclude WS handshake noise which is normal polling behavior
const LOKI_URL = 'http://loki:3100';
const QUERY = '{container="javisi_openclaw"} |~ `(?i)(error|fail|crash|panic|EROFS|timeout|429|500|reject|rate.limit|circuit.break|fallback.exhaust)` !~ `handshake timeout` !~ `closed before connect`';
const END = new Date();
const START = new Date(END.getTime() - 5 * 60 * 1000);

const url = `${LOKI_URL}/loki/api/v1/query_range?query=${encodeURIComponent(QUERY)}&start=${Math.floor(START.getTime() / 1000)}&end=${Math.floor(END.getTime() / 1000)}&limit=100`;

const resp = await fetch(url);
if (!resp.ok) {
  return [{ json: { errors: [], count: 0, lokiError: `HTTP ${resp.status}` } }];
}

const data = await resp.json();
const results = data?.data?.result || [];
const errors = [];

for (const stream of results) {
  for (const [ts, line] of (stream.values || [])) {
    errors.push({
      timestamp: new Date(parseInt(ts.slice(0, 13))).toISOString(),
      line: line.slice(0, 500),
      labels: stream.stream
    });
  }
}

return [{ json: { errors, count: errors.length } }];

const { errors } = $input.first().json;
const crypto = require('crypto');

// Get DLQ state from staticData
const staticData = $getWorkflowStaticData('global');
if (!staticData.dlq) staticData.dlq = {};
if (!staticData.stats) staticData.stats = { totalProcessed: 0, totalNew: 0, lastRun: null };

// Classification rules
function classify(line) {
  const lower = line.toLowerCase();
  if (lower.match(/crash|panic|fatal|segfault|oom/)) return 'critical';
  if (lower.match(/429|rate.limit|budget|circuit.break|fallback.exhaust/)) return 'high';
  if (lower.match(/timeout|500|fail|reject/)) return 'high';
  if (lower.match(/error|erofs|warn/)) return 'medium';
  return 'low';
}

// Deduplicate: hash the error line (stripped of timestamps and UUIDs)
function hashError(line) {
  const normalized = line
    .replace(/\d{4}-\d{2}-\d{2}T[\d:.+Z-]+/g, 'TS')
    .replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, 'UUID')
    .replace(/conn=[\w-]+/g, 'conn=X')
    .trim();
  return crypto.createHash('sha256').update(normalized).digest('hex').slice(0, 16);
}

const newErrors = [];
const now = Date.now();
const TTL = 60 * 60 * 1000; // 1 hour dedup window

// Clean expired entries
for (const [hash, entry] of Object.entries(staticData.dlq)) {
  if (now - entry.lastSeen > TTL) {
    delete staticData.dlq[hash];
  }
}

for (const err of errors) {
  const hash = hashError(err.line);
  const severity = classify(err.line);

  if (staticData.dlq[hash]) {
    // Already seen — increment count
    staticData.dlq[hash].count += 1;
    staticData.dlq[hash].lastSeen = now;
  } else {
    // New error — add to DLQ
    staticData.dlq[hash] = {
      firstSeen: now,
      lastSeen: now,
      count: 1,
      severity,
      sample: err.line.slice(0, 300)
    };
    newErrors.push({ hash, severity, line: err.line, timestamp: err.timestamp });
  }
}

// Stats
const dlqSize = Object.keys(staticData.dlq).length;
const criticalCount = Object.values(staticData.dlq).filter(e => e.severity === 'critical').length;
const highCount = Object.values(staticData.dlq).filter(e => e.severity === 'high').length;
const mediumCount = Object.values(staticData.dlq).filter(e => e.severity === 'medium').length;

staticData.stats.totalProcessed += errors.length;
staticData.stats.totalNew += newErrors.length;
staticData.stats.lastRun = new Date().toISOString();

return [{ json: {
  newErrors,
  newCount: newErrors.length,
  dlqSize,
  criticalCount,
  highCount,
  mediumCount,
  stats: staticData.stats
}}];

const { newErrors, dlqSize, criticalCount, highCount, mediumCount } = $input.first().json;
// HTML-escape untrusted log content to prevent injection in Telegram HTML messages
function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const sevEmoji = { critical: '🔴', high: '🟠', medium: '🟡', low: '⚪' };
const lines = [];

// Header
if (criticalCount > 0) {
  lines.push('🚨 <b>DLQ CRITICAL</b> — OpenClaw');
} else if (highCount > 0) {
  lines.push('⚠️ <b>DLQ Alert</b> — OpenClaw');
} else {
  lines.push('ℹ️ <b>DLQ Update</b> — OpenClaw');
}
lines.push('');

// New errors summary
lines.push(`<b>${newErrors.length}</b> nouvelle(s) erreur(s) detectee(s):`);
lines.push('');

for (const err of newErrors.slice(0, 5)) {
  const emoji = sevEmoji[err.severity] || '⚪';
  const shortLine = err.line.length > 120 ? err.line.slice(0, 120) + '...' : err.line;
  lines.push(`${emoji} [${err.severity.toUpperCase()}] <code>${esc(shortLine)}</code>`);
}

if (newErrors.length > 5) {
  lines.push(`... et ${newErrors.length - 5} autre(s)`);
}

// DLQ depth
lines.push('');
lines.push(`📊 DLQ depth: ${dlqSize} (🔴${criticalCount} 🟠${highCount} 🟡${mediumCount})`);

return [{ json: { message: lines.join('\n'), shouldAlert: criticalCount > 0 || highCount > 0 } }];

// No new errors — just update stats silently
const staticData = $getWorkflowStaticData('global');
if (!staticData.stats) staticData.stats = { totalProcessed: 0, totalNew: 0, lastRun: null };
staticData.stats.lastRun = new Date().toISOString();
return [{ json: { status: 'clean', dlqSize: Object.keys(staticData.dlq || {}).length } }];

// No errors at all in the last 5 min
const staticData = $getWorkflowStaticData('global');
if (!staticData.stats) staticData.stats = { totalProcessed: 0, totalNew: 0, lastRun: null };
staticData.stats.lastRun = new Date().toISOString();
return [{ json: { status: 'healthy', message: 'No errors in OpenClaw logs' } }];

// Return DLQ status for Grafana or external monitoring
// SECURITY: Truncate error samples to prevent sensitive data leakage via unauthenticated webhook
const staticData = $getWorkflowStaticData('global');
const dlq = staticData.dlq || {};
const stats = staticData.stats || { totalProcessed: 0, totalNew: 0, lastRun: null };

const entries = Object.entries(dlq).map(([hash, e]) => ({
  hash,
  severity: e.severity,
  count: e.count,
  sample: (e.sample || '').slice(0, 50).replace(/<[^>]*>/g, '').replace(/[\n\r]/g, ' '),
  firstSeen: new Date(e.firstSeen).toISOString(),
  lastSeen: new Date(e.lastSeen).toISOString()
}));

// Sort by severity then count
const sevOrder = { critical: 0, high: 1, medium: 2, low: 3 };
entries.sort((a, b) => (sevOrder[a.severity] - sevOrder[b.severity]) || (b.count - a.count));

const critical = entries.filter(e => e.severity === 'critical').length;
const high = entries.filter(e => e.severity === 'high').length;
const medium = entries.filter(e => e.severity === 'medium').length;

return [{ json: {
  dlqSize: entries.length,
  critical,
  high,
  medium,
  entries: entries.slice(0, 20),
  stats,
  timestamp: new Date().toISOString()
}}];
